        "    for i, mn in enumerate([\"VGG16\",\"MobileNetV2\",\"ResNet50\"]):\n",
        "        sub  = results_df[results_df[\"Model\"] == mn].sort_values(\"SimShort\")\n",
        "        bars = ax.bar(\n",
